import React from 'react';

const FIELDS = [
  { key: 'origin', label: 'Origin' },
  { key: 'characteristics', label: 'Characteristics' },
  { key: 'milk_production', label: 'Milk production' },
  { key: 'uses', label: 'Primary uses' },
  { key: 'fun_fact', label: 'Fun fact' },
];

export default function BreedInfoGrid({ breedName, info, loading, error }) {
  return (
    <section className="breed-panel">
      <div className="panel-header">
        <div>
          <p className="panel-label">Breed details</p>
          <h3>{breedName || 'Breed profile'}</h3>
        </div>
        <p className="panel-meta">AI-powered insights for the selected prediction</p>
      </div>

      {loading ? (
        <div className="breed-grid loading-grid">
          {FIELDS.map((field) => (
            <div key={field.key} className="breed-card skeleton-card">
              <div className="skeleton-title" />
              <div className="skeleton-copy" />
            </div>
          ))}
        </div>
      ) : error ? (
        <div className="panel-error">{error}</div>
      ) : (
        <div className="breed-grid">
          {FIELDS.map((field) => (
            <div key={field.key} className="breed-card">
              <div className="breed-card-label">{field.label}</div>
              <p>{info?.[field.key] || 'Information unavailable.'}</p>
            </div>
          ))}
        </div>
      )}
    </section>
  );
}
